import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeUserInput(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println("<p>" + sanitizedInput + "</p>"); // Display sanitized input in the HTML response
        out.println("</body>");
        out.println("</html>");

    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper sanitization logic based on your requirements
        // One common approach is to use a library like OWASP Java Encoder to escape special characters
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

